fn main() {
    let args: Vec<String> = std::env::args().collect();

    if args.len() < 2 {
        session_mode();
        return;
    }

    match args[1].as_str() {
        "--corvia-metadata" => {
            println!("{}", serde_json::to_string(&metadata()).unwrap());
        }
        _ => {
            eprintln!("Usage: corvia-adapter-git [--corvia-metadata]");
            eprintln!("  No args: session mode (read JSONL from stdin)");
            std::process::exit(1);
        }
    }
}
